import React from 'react';
import { Link } from 'react-router-dom';

export default function MovieCard({ movie }) {
  return (
    <Link to={`/movies/${movie.id}`} className="card">
      <div className="card-img">
        <img
          src={movie.posterUrl || '/default-movie.png'}
          alt={movie.title}
          onError={(e) => { e.target.style.display = 'none'; e.target.parentNode.innerHTML = '<span style="font-size:4rem;">🎬</span>'; }}
        />
      </div>
      <div className="card-body">
        <h3>{movie.title}</h3>
        <p>{movie.description || ''}</p>
        <div className="badges">
          {movie.genre && <span className="badge badge-genre">{movie.genre}</span>}
          {movie.language && <span className="badge badge-lang">{movie.language}</span>}
          {movie.rating && <span className="badge badge-rating">⭐ {movie.rating}</span>}
        </div>
      </div>
      <div className="card-footer">
        <span className="duration">{movie.durationMinutes ? `${movie.durationMinutes} min` : ''}</span>
        <span className="btn btn-sm btn-primary">Book Now</span>
      </div>
    </Link>
  );
}
